import io
import os
import uuid
import json
import shutil
import zipfile
import tempfile
from pathlib import Path
from typing import List, Optional

import numpy as np
import pandas as pd
from PIL import Image
from fastapi import FastAPI, UploadFile, File, Form, HTTPException
from fastapi.responses import JSONResponse
from pydantic import BaseModel
import tensorflow as tf

BASE_DIR = Path(os.getenv("APP_DATA_DIR", "app_data"))
UPLOADS_DIR = BASE_DIR / "uploads"
DATA_DIR = BASE_DIR / "dataset"
IMAGES_DIR = DATA_DIR / "images"
MODELS_DIR = BASE_DIR / "models"
METRICS_DIR = BASE_DIR / "metrics"

for d in [UPLOADS_DIR, DATA_DIR, IMAGES_DIR, MODELS_DIR, METRICS_DIR]:
    d.mkdir(parents=True, exist_ok=True)

CSV_PATH = DATA_DIR / "labels.csv"
LATEST_MODEL_DIR = MODELS_DIR / "latest"
IMG_SIZE = (224, 224)
BATCH_SIZE = 32
EPOCHS = 5
AUTOTUNE = tf.data.AUTOTUNE

app = FastAPI(title="Community Image Classifier")

def ensure_csv():
    if not CSV_PATH.exists():
        pd.DataFrame(columns=["image_path", "label", "contributor_id"]).to_csv(CSV_PATH, index=False)

ensure_csv()

class TrainResponse(BaseModel):
    status: str
    samples: int
    classes: List[str]
    model_path: str
    metrics_path: str

class DatasetStatusResponse(BaseModel):
    samples: int
    classes: List[str]
    class_counts: dict

def load_labels_df() -> pd.DataFrame:
    ensure_csv()
    df = pd.read_csv(CSV_PATH)
    if "image_path" not in df.columns or "label" not in df.columns:
        raise HTTPException(status_code=400, detail="Dataset CSV is invalid")
    df = df.dropna(subset=["image_path", "label"])
    df["image_path"] = df["image_path"].astype(str)
    df["label"] = df["label"].astype(str)
    if "contributor_id" not in df.columns:
        df["contributor_id"] = ""
    return df

def save_labels_df(df: pd.DataFrame):
    df.to_csv(CSV_PATH, index=False)

def normalize_label(label: str) -> str:
    label = str(label).strip()
    if not label:
        raise HTTPException(status_code=400, detail="Label cannot be empty")
    return label

def save_upload_file(upload: UploadFile, dest: Path):
    with dest.open("wb") as buffer:
        shutil.copyfileobj(upload.file, buffer)

def validate_and_save_image(upload: UploadFile, label: str, contributor_id: str = "") -> dict:
    ext = Path(upload.filename or "").suffix.lower()
    if ext not in [".jpg", ".jpeg", ".png", ".bmp", ".gif", ".webp"]:
        ext = ".jpg"
    image_id = f"{uuid.uuid4().hex}{ext}"
    image_dest = IMAGES_DIR / image_id
    temp_dest = UPLOADS_DIR / f"tmp_{image_id}"
    save_upload_file(upload, temp_dest)
    try:
        img = Image.open(temp_dest).convert("RGB")
        img.save(image_dest)
    except Exception:
        temp_dest.unlink(missing_ok=True)
        raise HTTPException(status_code=400, detail=f"Invalid image file: {upload.filename}")
    finally:
        temp_dest.unlink(missing_ok=True)
    df = load_labels_df()
    df = pd.concat(
        [
            df,
            pd.DataFrame(
                [{"image_path": str(image_dest), "label": normalize_label(label), "contributor_id": contributor_id}]
            ),
        ],
        ignore_index=True,
    )
    save_labels_df(df)
    return {"image_path": str(image_dest), "label": label, "contributor_id": contributor_id}

def import_csv_and_assets(csv_file: UploadFile, assets_zip: Optional[UploadFile] = None) -> dict:
    temp_dir = Path(tempfile.mkdtemp(dir=str(UPLOADS_DIR)))
    try:
        csv_path = temp_dir / "data.csv"
        save_upload_file(csv_file, csv_path)
        try:
            df_new = pd.read_csv(csv_path)
        except Exception:
            raise HTTPException(status_code=400, detail="Unable to parse CSV file")
        required = {"image_path", "label"}
        if not required.issubset(set(df_new.columns)):
            raise HTTPException(status_code=400, detail="CSV must contain columns: image_path,label")
        assets_dir = temp_dir / "assets"
        assets_dir.mkdir(exist_ok=True)
        if assets_zip is not None:
            zip_path = temp_dir / "assets.zip"
            save_upload_file(assets_zip, zip_path)
            try:
                with zipfile.ZipFile(zip_path, "r") as zf:
                    zf.extractall(assets_dir)
            except Exception:
                raise HTTPException(status_code=400, detail="Invalid ZIP file")
        imported_rows = []
        for _, row in df_new.iterrows():
            rel_or_abs_path = str(row["image_path"])
            label = normalize_label(row["label"])
            contributor_id = str(row["contributor_id"]) if "contributor_id" in df_new.columns else ""
            src = Path(rel_or_abs_path)
            if not src.is_absolute():
                src = assets_dir / rel_or_abs_path
            if not src.exists():
                continue
            ext = src.suffix.lower() if src.suffix else ".jpg"
            dest = IMAGES_DIR / f"{uuid.uuid4().hex}{ext}"
            try:
                img = Image.open(src).convert("RGB")
                img.save(dest)
                imported_rows.append(
                    {"image_path": str(dest), "label": label, "contributor_id": contributor_id}
                )
            except Exception:
                continue
        if not imported_rows:
            raise HTTPException(status_code=400, detail="No valid image rows could be imported from CSV")
        df_existing = load_labels_df()
        df_all = pd.concat([df_existing, pd.DataFrame(imported_rows)], ignore_index=True)
        save_labels_df(df_all)
        return {"imported": len(imported_rows)}
    finally:
        shutil.rmtree(temp_dir, ignore_errors=True)

def build_dataset(df: pd.DataFrame):
    existing = df[df["image_path"].apply(lambda p: Path(p).exists())].copy()
    if existing.empty:
        raise HTTPException(status_code=400, detail="No valid images available for training")
    class_names = sorted(existing["label"].unique().tolist())
    label_to_index = {label: i for i, label in enumerate(class_names)}
    paths = existing["image_path"].tolist()
    labels = existing["label"].map(label_to_index).astype(np.int32).to_numpy()

    ds = tf.data.Dataset.from_tensor_slices((paths, labels))

    def _load(path, label):
        img = tf.io.read_file(path)
        img = tf.io.decode_image(img, channels=3, expand_animations=False)
        img = tf.image.resize(img, IMG_SIZE)
        img = tf.cast(img, tf.float32) / 255.0
        return img, label

    ds = ds.shuffle(len(paths), reshuffle_each_iteration=True).map(_load, num_parallel_calls=AUTOTUNE)
    total = len(paths)
    val_size = max(1, int(total * 0.2)) if total > 1 else 0
    train_size = total - val_size
    train_ds = ds.take(train_size)
    val_ds = ds.skip(train_size) if val_size > 0 else None

    augment = tf.keras.Sequential(
        [
            tf.keras.layers.RandomFlip("horizontal"),
            tf.keras.layers.RandomRotation(0.05),
            tf.keras.layers.RandomZoom(0.1),
        ]
    )

    train_ds = train_ds.map(lambda x, y: (augment(x, training=True), y), num_parallel_calls=AUTOTUNE)
    train_ds = train_ds.batch(BATCH_SIZE).prefetch(AUTOTUNE)
    if val_ds is not None:
        val_ds = val_ds.batch(BATCH_SIZE).prefetch(AUTOTUNE)

    return train_ds, val_ds, class_names, total

def build_model(num_classes: int):
    base = tf.keras.applications.MobileNetV2(
        input_shape=(IMG_SIZE[0], IMG_SIZE[1], 3),
        include_top=False,
        weights="imagenet",
    )
    base.trainable = False
    inputs = tf.keras.Input(shape=(IMG_SIZE[0], IMG_SIZE[1], 3))
    x = tf.keras.applications.mobilenet_v2.preprocess_input(inputs * 255.0)
    x = base(x, training=False)
    x = tf.keras.layers.GlobalAveragePooling2D()(x)
    x = tf.keras.layers.Dropout(0.2)(x)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    model = tf.keras.Model(inputs, outputs)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model

def write_metadata(class_names: List[str], metrics: dict, model_dir: Path):
    metadata = {
        "class_names": class_names,
        "metrics": metrics,
        "image_size": IMG_SIZE,
        "batch_size": BATCH_SIZE,
        "epochs": EPOCHS,
    }
    with (model_dir / "metadata.json").open("w", encoding="utf-8") as f:
        json.dump(metadata, f, indent=2)

def train_current_dataset() -> TrainResponse:
    df = load_labels_df()
    train_ds, val_ds, class_names, total = build_dataset(df)
    if len(class_names) < 2:
        raise HTTPException(status_code=400, detail="At least 2 classes are required for training")
    run_dir = MODELS_DIR / f"run_{uuid.uuid4().hex}"
    run_dir.mkdir(parents=True, exist_ok=True)
    model = build_model(len(class_names))
    callbacks = [
        tf.keras.callbacks.EarlyStopping(monitor="val_loss", patience=2, restore_best_weights=True)
    ]
    history = model.fit(
        train_ds,
        validation_data=val_ds if val_ds is not None else None,
        epochs=EPOCHS,
        callbacks=callbacks,
        verbose=1,
    )
    export_dir = run_dir / "saved_model"
    model.export(str(export_dir))
    metrics = {
        "final_train_loss": float(history.history["loss"][-1]),
        "final_train_accuracy": float(history.history["accuracy"][-1]),
    }
    if "val_loss" in history.history:
        metrics["final_val_loss"] = float(history.history["val_loss"][-1])
    if "val_accuracy" in history.history:
        metrics["final_val_accuracy"] = float(history.history["val_accuracy"][-1])

    metrics_path = METRICS_DIR / f"{run_dir.name}_metrics.json"
    with metrics_path.open("w", encoding="utf-8") as f:
        json.dump(metrics, f, indent=2)

    if LATEST_MODEL_DIR.exists():
        shutil.rmtree(LATEST_MODEL_DIR)
    shutil.copytree(run_dir, LATEST_MODEL_DIR)
    write_metadata(class_names, metrics, export_dir)

    return TrainResponse(
        status="trained",
        samples=total,
        classes=class_names,
        model_path=str(export_dir),
        metrics_path=str(metrics_path),
    )

@app.get("/status", response_model=DatasetStatusResponse)
def status():
    df = load_labels_df()
    existing = df[df["image_path"].apply(lambda p: Path(p).exists())]
    class_counts = existing["label"].value_counts().to_dict() if not existing.empty else {}
    return DatasetStatusResponse(
        samples=int(len(existing)),
        classes=sorted(existing["label"].unique().tolist()) if not existing.empty else [],
        class_counts=class_counts,
    )

@app.post("/contribute/image")
def contribute_image(
    file: UploadFile = File(...),
    label: str = Form(...),
    contributor_id: str = Form(default=""),
):
    record = validate_and_save_image(file, label, contributor_id)
    return JSONResponse({"status": "accepted", "record": record})

@app.post("/contribute/batch")
def contribute_batch(
    csv_file: UploadFile = File(...),
    assets_zip: Optional[UploadFile] = File(default=None),
):
    result = import_csv_and_assets(csv_file, assets_zip)
    return JSONResponse({"status": "accepted", **result})

@app.post("/train", response_model=TrainResponse)
def train():
    return train_current_dataset()

@app.post("/predict")
def predict(file: UploadFile = File(...)):
    model_dir = LATEST_MODEL_DIR / "saved_model"
    metadata_path = model_dir / "metadata.json"
    if not model_dir.exists() or not metadata_path.exists():
        raise HTTPException(status_code=404, detail="No trained model available")
    try:
        model = tf.saved_model.load(str(model_dir))
        with metadata_path.open("r", encoding="utf-8") as f:
            metadata = json.load(f)
        class_names = metadata["class_names"]
    except Exception:
        raise HTTPException(status_code=500, detail="Failed to load model")
    contents = file.file.read()
    try:
        img = Image.open(io.BytesIO(contents)).convert("RGB").resize(IMG_SIZE)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")
    arr = np.asarray(img).astype(np.float32) / 255.0
    arr = np.expand_dims(arr, axis=0)
    infer = model.signatures["serve"]
    outputs = infer(tf.constant(arr))
    pred = list(outputs.values())[0].numpy()[0]
    idx = int(np.argmax(pred))
    return {
        "predicted_label": class_names[idx],
        "confidence": float(pred[idx]),
        "probabilities": {class_names[i]: float(pred[i]) for i in range(len(class_names))},
    }

